hints.text:
Insert this rule as the first entry in `rules`:
```json
{
  "rulePriority": 1,
  "description": "Protect production tags",
  "selection": {
    "tagStatus": "tagged",
    "tagPatternList": ["prod-*", "release-*"],
    "countType": "imageCountMoreThan",
    "countNumber": 9999
  },
  "action": { "type": "expire" }
}
```
Then update the cleanup rule to `rulePriority: 2`.

solution:
apiVersion: v1
kind: ConfigMap
metadata:
  name: ecr-lifecycle-policy
  namespace: default
data:
  policy.json: |
    {
      "rules": [
        {
          "rulePriority": 1,
          "description": "Protect production tags",
          "selection": {
            "tagStatus": "tagged",
            "tagPatternList": ["prod-*", "release-*"],
            "countType": "imageCountMoreThan",
            "countNumber": 9999
          },
          "action": { "type": "expire" }
        },
        {
          "rulePriority": 2,
          "description": "Expire old images",
          "selection": {
            "tagStatus": "any",
            "countType": "imageCountMoreThan",
            "countNumber": 10
          },
          "action": { "type": "expire" }
        }
      ]
    }
